def _apply_user_key_customizations():  # isort: skip
    """UserKey-specific overrides applied at import time.

    Wrapped in a function so ansible-doc's AST parser does not choke on
    attribute patches at module level.
    """
    from typing import Any, Dict, List, Optional

    from ansible_collections.vastdata.vms.plugins.module_utils.vast.errors import VastAPIError

    UserKey.module_result_key = "result"

    def _user_key_run(self) -> None:
        state = self.params.get("state", "present")

        if state == "absent":
            payload = self._build_payload()
            if not self.check_mode:
                try:
                    self._api_base.delete(**payload)
                except Exception as e:
                    self.module.fail_json(msg=f"Failed to delete {self.sub_path}: {e}")
            self.module.exit_json(changed=True, result={})

        access_key = self.params.get("access_key")
        if access_key:
            current = self._get_current_key()
            if current:
                self._perform_update(current)
                return

        self._perform_create()

    def _user_key_lookup_access_keys(self, user: Dict[str, Any], tenant_id: Optional[int]) -> List[Dict[str, Any]]:
        """Return access_keys for the user, scoped to tenant_id when provided."""
        access_keys = list(user.get("access_keys", []))

        if tenant_id is None:
            return access_keys

        identity_params: Dict[str, Any] = {"tenant_id": tenant_id}
        if user.get("uid") is not None:
            identity_params["uid"] = user["uid"]
        elif user.get("name"):
            identity_params["username"] = user["name"]
        elif user.get("vid") is not None:
            identity_params["vid"] = user["vid"]
            identity_params["context"] = "udb"
        else:
            return access_keys

        try:
            query_results = self.client.api["users"]["query"].get(**identity_params)
        except VastAPIError as e:
            self.module.warn(f"Tenant-scoped user query failed, falling back: {e}")
            return access_keys

        if not query_results:
            return access_keys

        return [{"tenant_id": tenant_id, **k} for k in query_results[0].get("access_keys", [])]

    def _user_key_get_current_key(self) -> Optional[Dict[str, Any]]:
        access_key = self.params.get("access_key")
        if not access_key:
            return None

        try:
            user_id = self.params[self.parent_id_param]
            users = self.client.api["users"][user_id].get()
            if not users:
                return None

            user = users[0]
            tenant_id = self.params.get("tenant_id")
            access_keys = self._lookup_access_keys(user, tenant_id)

            for key in access_keys:
                if key.get("access_key") != access_key:
                    continue
                if tenant_id is None or key.get("tenant_id") == tenant_id:
                    return key

            return None

        except Exception as e:
            self.module.warn(f"Could not verify existing key: {e}")
            return None

    def _user_key_perform_update(self, current: Dict[str, Any]) -> None:
        payload = self._build_payload()

        if not payload:
            self.module.exit_json(changed=False, **{self.module_result_key: current})

        changed = False
        for key, value in payload.items():
            if key in self.identity_params:
                continue
            if current.get(key) != value:
                changed = True
                break

        if not changed:
            self.module.exit_json(changed=False, **{self.module_result_key: current})

        diff_before = dict(current)

        if not self.check_mode:
            try:
                result = self.update(payload)

                if not result or not result.get("access_key"):
                    result = self._get_current_key() or result

            except VastAPIError as e:
                self.module.fail_json(msg=str(e))
            diff_after = dict(result) if result else {**diff_before, **payload}
        else:
            result = {**current, **payload}
            diff_after = result

        output = {"changed": True, self.module_result_key: result, "diff": {"before": diff_before, "after": diff_after}}
        self.module.exit_json(**output)

    def _user_key_perform_create(self) -> None:
        payload = self._build_payload()

        if not self.check_mode:
            try:
                result = self.create(payload)
            except VastAPIError as e:
                self.module.fail_json(msg=str(e))
        else:
            result = payload

        self.module.exit_json(changed=True, **{self.module_result_key: result})

    UserKey.run = _user_key_run
    UserKey._lookup_access_keys = _user_key_lookup_access_keys
    UserKey._get_current_key = _user_key_get_current_key
    UserKey._perform_update = _user_key_perform_update
    UserKey._perform_create = _user_key_perform_create


_apply_user_key_customizations()


